module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output dout_valid
);
    reg [2:0] cnt;

    always @(posedge clk) begin
        if (!rst_n) begin
            cnt <= 3'd0;
            dout_parallel <= 8'd0;
        end
        else if (din_valid) begin
            dout_parallel[7-cnt] <= din_serial;
            if (cnt == 3'd7) cnt <= 3'd0;
            else cnt <= cnt + 1;
        end
    end

    always @(posedge clk) begin
        if (!rst_n) dout_valid <= 1'b0;
        else if (cnt == 3'd7) dout_valid <= 1'b1;
        else dout_valid <= 1'b0;
    end
endmodule

module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
//YOUR CODE HERE
reg [7:0] dividend_r, divisor_r;
reg [15:0] SR, NEG_DIVISOR;
reg [3:0] cnt;
reg start_cnt;
reg carry_out, subtraction_result;
reg [15:0] remainder, quotient;
always @(posedge clk or negedge rst) begin
    if (!rst) begin
        dividend_r <= 8'b0;
        divisor_r <= 8'b0;
        cnt <= 4'b0;
        start_cnt <= 1'b0;
        result <= 16'b0;
        remainder <= 16'b0;
        quotient <= 16'b0;
        start_cnt <= 1'b0;
        carry_out <= 1'b0;
        subtraction_result <= 1'b0;
        SR <= 16'b0;
        NEG_DIVISOR <= 16'b0;
    end else begin
        if (opn_valid == 1'b1 && res_valid == 1'b0) begin
            dividend_r <= dividend;
            divisor_r <= divisor;
            SR <= {dividend, 8'b0}; // Initialize SR with the dividend shifted left by 8 bits
            NEG_DIVISOR <= (~{divisor, 8'b0}) + 1; // Negate the divisor and shift it left by 8 bits
            cnt <= 4'b0001; // Set the counter to 1
            start_cnt <= 1'b1; // Set start_cnt to 1 to start the division process
        end else if (start_cnt) begin
            if (cnt[3] == 1'b1) begin
                cnt <= 4'b0; // Reset the counter when the most significant bit is 1
                start_cnt <= 1'b0; // Reset start_cnt to 0 to end the division process
                result <= SR; // Set the result to the content of SR
                remainder <= SR; // Set the remainder to the content of SR
                quotient <= quotient; // Keep the quotient unchanged
            end else begin
                cnt <= cnt + 1; // Increment the counter by 1
                if (remainder >= 0) begin
                    carry_out <= 1'b1; // Set carry_out to 1 if the subtraction result is non-negative
                    remainder <= subtraction_result; // Set the remainder to the subtraction result
                end else begin
                    carry_out <= 1'b0; // Set carry_out to 0 if the subtraction result is negative
                    remainder <= subtraction_result; // Set the remainder to the subtraction result
                end
                SR <= {SR[14:0], carry_out}; // Shift the SR to the left by 1 bit and insert the carry_out at LSB
                subtraction_result <= remainder - NEG_DIVISOR; // Subtract the divisor from the remainder
            end
        end
        if (rst) begin
            res_valid <= 1'b0;
        end else begin
            if (cnt == 4'b1000) begin
                res_valid <= 1'b1;
            end else if (res_valid && res_ready) begin
                res_valid <= 1'b0;
            end
        end
    end
end
endmodule

module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
); 
//write your code here
// you can modify the module, add your own parameters, wires, reg, etc.
// but do not change the module name and the input and output ports
// declare your parameters here
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
// declare your wires and reg here
reg [7:0] cnt;
reg [1:0] state;
reg p_red;
reg p_yellow;
reg p_green;
// implement your logic here
always@(*)begin
    case(state)
        idle:begin
            state <= s1_red;
        end
        s1_red:begin
            if(cnt==3) state <= s3_green;
            else state <= s1_red;
        end
        s2_yellow:begin
            if(cnt==3) state <= s1_red;
            else state <= s2_yellow;
        end
        s3_green:begin
            if(cnt==3) state <= s2_yellow;
            else state <= s3_green;
        end
        default:begin
            state <= idle;
        end
    endcase
end
always@(posedge clk or negedge rst_n)begin
    if(!rst_n)cnt<=10;
    else begin
        if(pass_request&&green)cnt<=10;
        else if(!green&&p_green)cnt<=60;
        else if(!yellow&&p_yellow)cnt<=5;
        else if(!red&&p_red)cnt<=10;
        else cnt<=cnt-1;
    end
end
always@(*)begin
    clock = cnt;
end
always@(posedge clk or negedge rst_n)begin
    if(!rst_n)begin
        red <= 0;
        yellow <= 0;
        green <= 0;
    end
    else begin
        red <= p_red;
        yellow <= p_yellow;
        green <= p_green;
    end
end
always@(*)begin
    case(state)
        idle:begin
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
        end
        s1_red:begin
            p_red = 1;
            p_yellow = 0;
            p_green = 0;
        end
        s2_yellow:begin
            p_red = 0;
            p_yellow = 1;
            p_green = 0;
        end
        s3_green:begin
            p_red = 0;
            p_yellow = 0;
            p_green = 1;
        end
        default:begin
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
        end
    endcase
end
endmodule

module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

reg [15:0] a, b;
reg [31:0] p;
reg [4:0] i;
reg done_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a <= 0;
        b <= 0;
        p <= 0;
        i <= 0;
        done_r <= 0;
    end
    else if (start) begin
        if (i == 0) begin
            a <= ain;
            b <= bin;
        end
        else if (i < 16) begin
            if (b[0]) begin
                p <= p + (a << (i - 1));
            end
            b <= b >> 1;
            i <= i + 1;
        end
        else begin
            done_r <= 1;
        end
    end
    else begin
        p <= 0;
        i <= 0;
        done_r <= 0;
    end
end

assign yout = p;
assign done = done_r;

endmodule

