module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [3:0] shift_reg;
reg [1:0] counter;
reg valid;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        shift_reg <= 4'b0;
        counter <= 2'b0;
        valid <= 1'b0;
    end
    else begin
        if (counter == 2'b11) begin
            shift_reg <= d;
            counter <= 2'b0;
            valid <= 1'b1;
        end
        else begin
            shift_reg <= {shift_reg[2:0], 1'b0};
            counter <= counter + 1'b1;
            valid <= 1'b1;
        end
    end
end

assign valid_out = valid;
assign dout = shift_reg[3];

endmodule

module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output [15:0] odd
);

always @(*) begin
    if (A[15:8] >= B) begin
        result = {8'b0, 1'b1, A[7:0]};
    end else begin
        result = {8'b0, 1'b0, A[7:0]};
    end
end

assign odd = A - (result[15:8] * B);

endmodule

module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    reg [3:0] shift_count;
    reg [7:0] multiplier;
    reg [15:0] accumulator;

    always @(*) begin
        partial_product = 0;
        shift_count = 0;
        multiplier = B;
        accumulator = 0;

        for (int i = 0; i < 8; i = i + 1) begin
            if (multiplier[0]) begin
                partial_product = partial_product + (A << i);
            end
            multiplier = multiplier >> 1;
        end

        product = partial_product;
    end

endmodule

module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);

reg [2:0] state;
reg [2:0] next_state;
reg match_reg;

localparam STATE_IDLE = 3'b000;
localparam STATE_1 = 3'b001;
localparam STATE_10 = 3'b010;
localparam STATE_100 = 3'b011;
localparam STATE_1001 = 3'b100;
localparam STATE_10011 = 3'b101;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= STATE_IDLE;
        match_reg <= 1'b0;
    end else begin
        state <= next_state;
        match_reg <= (state == STATE_10011) ? 1'b1 : 1'b0;
    end
end

always @(*) begin
    case (state)
        STATE_IDLE: begin
            if (IN) begin
                next_state = STATE_1;
            end else begin
                next_state = STATE_IDLE;
            end
        end
        STATE_1: begin
            if (IN) begin
                next_state = STATE_1;
            end else begin
                next_state = STATE_10;
            end
        end
        STATE_10: begin
            if (IN) begin
                next_state = STATE_1;
            end else begin
                next_state = STATE_100;
            end
        end
        STATE_100: begin
            if (IN) begin
                next_state = STATE_1001;
            end else begin
                next_state = STATE_IDLE;
            end
        end
        STATE_1001: begin
            if (IN) begin
                next_state = STATE_10011;
            end else begin
                next_state = STATE_100;
            end
        end
        STATE_10011: begin
            next_state = STATE_IDLE;
        end
        default: begin
            next_state = STATE_IDLE;
        end
    endcase
end

assign MATCH = match_reg;

endmodule

module freq_div(
