module edge_detect(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

reg a_prev;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a_prev <= 1'b0;
        rise <= 1'b0;
        down <= 1'b0;
    end else begin
        if (a_prev == 1'b0 && a == 1'b1) begin
            rise <= 1'b1;
            down <= 1'b0;
        end else if (a_prev == 1'b1 && a == 1'b0) begin
            rise <= 1'b0;
            down <= 1'b1;
        end else begin
            rise <= 1'b0;
            down <= 1'b0;
        end
        a_prev <= a;
    end
end

endmodule

module adder_16bit(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [7:0] sum_low;
    wire [7:0] sum_high;
    wire carry;

    // Lower 8-bit adder
    assign {carry, sum_low} = a[7:0] + b[7:0] + Cin;

    // Upper 8-bit adder
    assign {Co, sum_high} = a[15:8] + b[15:8] + carry;

    // Concatenate the results
    assign y = {sum_high, sum_low};

endmodule

module multi_pipe_4bit(
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

parameter SIZE = 4;

reg [SIZE-1:0] reg1, reg2, reg3, reg4;
reg [SIZE:0] reg5, reg6, reg7;
reg [(SIZE*(SIZE-1))/2:0] partial_products;

always @(*) begin
    if (!rst_n) begin
        partial_products = 0;
    end else begin
        partial_products = {4'b0, mul_a};
        for (int i = 0; i < SIZE; i++) begin
            if (mul_b[i]) begin
                partial_products = partial_products + (mul_a << i);
            end
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg1 <= 0;
        reg2 <= 0;
        reg3 <= 0;
        reg4 <= 0;
        reg5 <= 0;
        reg6 <= 0;
        reg7 <= 0;
    end else begin
        reg1 <= partial_products[(SIZE*(SIZE-1))/2 - 1:(SIZE-1)/2];
        reg2 <= partial_products[(SIZE-1)/2 - 1:(SIZE-1)%2];
        reg3 <= partial_products[(SIZE-1)%2 - 1:0];
        reg4 <= partial_products[SIZE - 1:0];
        reg5 <= reg1 + reg2;
        reg6 <= reg3 + reg4;
        reg7 <= reg5 + reg6;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 0;
    end else begin
        mul_out <= reg5 + reg7;
    end
end

endmodule

module calendar(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

reg [5:0] sec_reg, min_reg, hour_reg;
reg [5:0] sec_next, min_next, hour_next;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        sec_reg <= 6'd0;
        min_reg <= 6'd0;
        hour_reg <= 6'd0;
    end
    else begin
        sec_reg <= sec_next;
        min_reg <= min_next;
        hour_reg <= hour_next;
    end
end

always @* begin
    sec_next = sec_reg + 6'd1;
    min_next = min_reg;
    hour_next = hour_reg;

    if (sec_reg == 6'd59) begin
        sec_next = 6'd0;
        min_next = min_reg + 6'd1;
    end

    if (min_reg == 6'd59 && sec_reg == 6'd59) begin
        min_next = 6'd0;
        hour_next = hour_reg + 6'd1;
    end

    if (hour_reg == 6'd23 && min_reg == 6'd59 && sec_reg == 6'd59) begin
        hour_next = 6'd0;
    end
end

assign Secs = sec_reg;
assign Mins = min_reg;
assign Hours = hour_reg;

endmodule

module asyn_fifo #(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)(
    input wclk,
    input rclk,
    input rst_n,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output wfull,
    output rempty,
    output reg [WIDTH-1:0] rdata
);

    localparam ADDR_WIDTH = $clog2(DEPTH);

    wire [ADDR_WIDTH-1:0] waddr, raddr;
    wire [WIDTH-1:0] rdata_w;
    wire wenc, renc;
    wire [WIDTH-1:0] wdata_w;
    reg [WIDTH-1:0] rdata;
    reg [WIDTH-1:0] RAM_MEM[0:DEPTH-1];

    // Write enable and read enable
    assign wenc = winc & ~wfull;
    assign renc = rinc & ~rempty;

    // Write data
    always @(posedge wclk) begin
        if (wenc) RAM_MEM[waddr] <= wdata_w;
    end

    // Read data
    assign rdata_w = RAM_MEM[raddr];

    // Write pointer
    reg [ADDR_WIDTH:0] wptr;
    always @(posedge wclk or negedge rst_n) begin
        if (!rst_n) begin
            wptr <= 0;
        end
        else if (winc) begin
            wptr <= wptr + 1;
        end
    end

    // Read pointer
    reg [ADDR_WIDTH:0] rptr;
    always @(posedge rclk or negedge rst_n) begin
        if (!rst_n) begin
            rptr <= 0;
        end
        else if (rinc) begin
            rptr <= rptr + 1;
        end
    end

    // Gray code conversion
    reg [ADDR_WIDTH:0] wptr_gray, rptr_gray;
    always @(posedge wclk or negedge rst_n) begin
        if (!rst_n) begin
            wptr_gray <= 0;
        end
        else begin
            wptr_gray <= wptr ^ (wptr >> 1);
        end
    end

    always @(posedge rclk or negedge rst_n) begin
        if (!rst_n) begin
            rptr_gray <= 0;
        end
        else begin
            rptr_gray <= rptr ^ (rptr >> 1);
        end
    end

    // Read pointer buffer
    reg [ADDR_WIDTH:0] rptr_buff;
    always @(posedge rclk or negedge rst_n) begin
        if (!rst_n) begin
            rptr_buff <= 0;
        end
        else begin
            rptr_buff <= rptr_gray;
        end
    end

    // Write pointer buffer
    reg [ADDR_WIDTH:0] wptr_buff;
    always @(posedge wclk or negedge rst_n) begin
        if (!rst_n) begin
            wptr_buff <= 0;
        end
        else begin
            wptr_buff <= wptr_gray;
        end
    end

    // Full and empty
    assign waddr = wptr_buff[ADDR_WIDTH-1:0];
    assign raddr = rptr_buff[ADDR_WIDTH-1:0];
    assign wfull = (wptr_buff[ADDR_WIDTH] ^ wptr_buff[ADDR_WIDTH-1:0]) == rptr_buff[ADDR_WIDTH-1:0];
    assign rempty = (wptr_buff == rptr_buff);

    // Output read data
    always @(posedge rclk or negedge rst_n) begin
        if (!rst_n) begin
            rdata <= 0;
        end
        else begin
            rdata <= rdata_w;
        end
    end

    // Assign the output port
    assign rdata = rdata;

endmodule

module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [32:1] C;
wire [32:1] P;
wire [32:1] G;

assign P[32:1] = A[32:1] ^ B[32:1];
assign G[32:1] = A[32:1] & B[32:1];

assign C[1] = P[1] & C[0];
generate
    genvar i;
    for (i = 2; i <= 32; i = i + 1) begin
        assign C[i] = (P[i] & C[i-1]) | G[i];
    end
endgenerate

assign S[32:1] = P[32:1] ^ {C[32:1], 1'b0};
assign C32 = C[32];

endmodule

module signal_generator(
    input clk,
    input rst_n,
    output [4:0] wave
);

reg [4:0] wave_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        wave_reg <= 5'b0;
    end else begin
        if (wave_reg == 5'd31) begin
            wave_reg <= 5'd30;
        end else if (wave_reg == 5'd0) begin
            wave_reg <= 5'd1;
        end else if (wave_reg[4] == 1'b0) begin
            wave_reg <= wave_reg + 1'b1;
        end else begin
            wave_reg <= wave_reg - 1'b1;
        end
    end
end

assign wave = wave_reg;

endmodule

module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output o_en
);

reg [63:0] adda_reg, addb_reg;
reg i_en_reg;
reg [64:0] result_reg;
reg o_en_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        adda_reg <= 64'b0;
        addb_reg <= 64'b0;
        i_en_reg <= 1'b0;
        result_reg <= 65'b0;
        o_en_reg <= 1'b0;
    end else begin
        adda_reg <= adda;
        addb_reg <= addb;
        i_en_reg <= i_en;
        result_reg <= adda_reg + addb_reg;
        o_en_reg <= i_en_reg;
    end
end

assign result = result_reg;
assign o_en = o_en_reg;

endmodule

